  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="24" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">CME v. CFTC — timeline of the Kalshi BTCPERP lawsuit</text>
    <text x="24" y="54" fill="#a1a1aa" font-size="13" font-family="sans-serif">U.S. District Court for D.C., case pending</text>
