      <line x1="40" y1="100" x2="660" y2="100" stroke="#3f3f46" stroke-width="2"/>
      <circle cx="70" cy="100" r="6" fill="#a1a1aa"/><text x="70" y="126" fill="#e4e4e7" font-size="12.5" text-anchor="middle">29 мая</text><text x="70" y="142" fill="#a1a1aa" font-size="12.5" text-anchor="middle">Одобрение по Правилу 40.2</text>
